output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?shogunateLabel ?battleLabel WHERE {
  VALUES ?shogunate {
    wd:Q736839 wd:Q1154406 wd:Q205662
  }
  ?shogunate wdt:P607 ?conflict .
  ?battle wdt:P31 wd:Q178561 ; wdt:P361 ?conflict .
  ?shogunate rdfs:label ?shogunateLabel .
  ?battle rdfs:label ?battleLabel .
  FILTER(LANG(?shogunateLabel) = "en" && LANG(?battleLabel) = "en")
}
